#include <vector>
#include <queue>
#include <climits>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        adj[u].push_back({v, w});
    }

    // Dijkstra's algorithm with state (node, switch_used)
    // switch_used is a boolean indicating whether the switch at the node has been used
    priority_queue<pair<long long, pair<long long, bool>>, vector<pair<long long, pair<long long, bool>>>, greater<pair<long long, pair<long long, bool>>>> pq;
    vector<vector<long long>> dist(n, vector<long long>(2, LONG_MAX));
    dist[0][0] = 0;
    pq.push({0, {0, 0}});

    while (!pq.empty()) {
        long long cost = pq.top().first;
        long long u = pq.top().second.first;
        bool switch_used = pq.top().second.second;
        pq.pop();

        if (u == n - 1) {
            return cost;
        }

        if (cost > dist[u][switch_used]) {
            continue;
        }

        // Traverse normal edges
        for (auto& [v, w] : adj[u]) {
            long long new_cost = cost + w;
            if (new_cost < dist[v][switch_used]) {
                dist[v][switch_used] = new_cost;
                pq.push({new_cost, {v, switch_used}});
            }
        }

        // If switch is not used, consider reversing the edge
        if (!switch_used) {
            for (auto& [v, w] : adj[u]) {
                long long new_cost = cost + 2 * w;
                if (new_cost < dist[v][true]) {
                    dist[v][true] = new_cost;
                    pq.push({new_cost, {v, true}});
                }
            }
        }
    }

    return -1;
}

